/* Base Resets */
    body {
      margin: 0;
      font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      background-color: var(--bg-body);
      color: var(--text);
      overflow-x: hidden;
      padding-top: var(--header-h); 
    }
    @media (max-width: 991px) { body { padding-top: 64px; } }

    a { text-decoration: none; color: var(--primary); transition: color var(--t); }
    a:hover { color: var(--primary-2); }
    p { line-height: 1.7; color: var(--text-s); font-size: 0.95rem; }

    .font-syne { font-family: 'Syne', sans-serif; }

    /* ========================================================================== */
    /* COMPONENTS & TYPOGRAPHY                                                    */
    /* ========================================================================== */
    .section-title {
      position: relative; padding-bottom: .75rem; margin-bottom: 2.5rem;
      font-weight: 800; color: var(--primary-d); font-family: 'Syne', sans-serif;
      font-size: clamp(1.6rem, 4vw, 2.2rem);
    }
    .section-title::after {
      content: ''; position: absolute; bottom: 0; left: 0;
      width: 60px; height: 4px; border-radius: 2px;
      background: linear-gradient(90deg, var(--primary), var(--gold));
    }
    .section-title.center::after { left: 50%; transform: translateX(-50%); }

    .btn-primary-custom {
      display: inline-flex; align-items: center; gap: 8px; 
      background: var(--primary); color: #fff; font-weight: 700; font-size: .95rem; 
      padding: 14px 32px; border-radius: 50px; border: none; 
      transition: all var(--t); box-shadow: 0 4px 12px rgba(0,102,255,0.2);
    }
    .btn-primary-custom:hover {
      background: var(--primary-2); transform: translateY(-2px); color: #fff;
      box-shadow: 0 6px 16px rgba(0,102,255,0.3);
    }

    .hover-lift { transition: transform 0.3s var(--ease), box-shadow 0.3s var(--ease), border-color 0.3s; }
    .hover-lift:hover { transform: translateY(-6px); box-shadow: var(--sh-md); border-color: rgba(51,133,255,0.15); z-index: 2; }

    /* ========================================================================== */
    /* HERO SECTION                                                               */
    /* ========================================================================== */
    .hero-banner {
      position: relative; overflow: hidden;
      background: linear-gradient(135deg, var(--digital-blue-950) 0%, var(--digital-blue-900) 50%, var(--digital-blue-800) 100%);
      padding: 80px 0 100px; text-align: center;
    }
    .hero-banner::before {
      content: ''; position: absolute; inset: 0;
      background-image: 
        radial-gradient(circle at 15% 50%, rgba(51, 133, 255, 0.2), transparent 30%),
        radial-gradient(circle at 85% 30%, rgba(51, 133, 255, 0.2), transparent 30%);
      z-index: 1; pointer-events: none;
    }
    .hero-ring {
      position: absolute; border-radius: 50%; border: 1px solid rgba(255,255,255,.05);
      pointer-events: none; z-index: 1;
    }
    .hero-ring-1 { width: 600px; height: 600px; top: -200px; left: -150px; border-color: rgba(51, 133, 255, 0.15); }
    .hero-ring-2 { width: 400px; height: 400px; bottom: -100px; right: -50px; border-color: rgba(255,255,255,.05); }

    .hero-content { position: relative; z-index: 3; max-width: 800px; margin: 0 auto; }
    .hero-breadcrumb {
      display: inline-flex; align-items: center; gap: 8px;
      color: var(--gold); font-size: .75rem; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em;
      background: rgba(51, 133, 255, 0.15); border: 1px solid rgba(51, 133, 255, 0.3);
      border-radius: 50px; padding: 6px 16px; margin-bottom: 24px;
      transition: all var(--t);
    }
    .hero-breadcrumb:hover { background: rgba(51, 133, 255, 0.25); color: #fff; transform: translateY(-2px); }
    .hero-banner h1 {
      font-size: clamp(2.5rem, 5vw, 3.8rem); font-weight: 800; color: #fff; 
      letter-spacing: -.02em; margin-bottom: 16px; text-shadow: 0 4px 20px rgba(0,0,0,0.3);
    }
    .hero-banner p {
      font-size: 1.15rem; color: rgba(255,255,255,.75); line-height: 1.7; margin-bottom: 0;
    }

    /* ========================================================================== */
    /* STATS ROW                                                                  */
    /* ========================================================================== */
    .stats-section { margin-top: -50px; position: relative; z-index: 10; padding-bottom: 60px; }
    .stat-box {
      background: #fff; border: 1px solid var(--bdr); border-radius: var(--r-md); 
      padding: 30px 20px; text-align: center; box-shadow: var(--sh-sm);
    }
    .stat-num { font-family: 'Syne', sans-serif; font-size: 2.5rem; font-weight: 800; color: var(--primary); line-height: 1; }
    .stat-lbl { font-size: .75rem; font-weight: 700; color: var(--text-m); margin-top: 8px; text-transform: uppercase; letter-spacing: .05em; }

    /* ========================================================================== */
    /* ADMISSION PROGRAMS                                                         */
    /* ========================================================================== */
    .prog-card { 
      background: #fff; border: 1px solid var(--bdr); border-radius: var(--r-lg); 
      overflow: hidden; margin-bottom: 32px; box-shadow: var(--sh-sm); 
    }
    .prog-header { 
      background: linear-gradient(135deg, var(--digital-blue-50), #fff); 
      padding: 24px 32px; display: flex; align-items: center; gap: 16px; 
      border-bottom: 1px solid var(--bdr-s);
    }
    .prog-header h3 { color: var(--primary-d); font-size: 1.35rem; font-weight: 800; margin: 0; font-family: 'Syne', sans-serif;}
    .prog-header .ph-icon { font-size: 2rem; width: 56px; height: 56px; display: flex; align-items: center; justify-content: center; background: var(--primary); color: #fff; border-radius: 14px; box-shadow: var(--sh-sm);}
    .prog-body { padding: 32px; }

    .criteria-list { list-style: none; padding: 0; margin: 0; }
    .criteria-list li {
      padding: 10px 0 10px 28px; position: relative;
      font-size: .95rem; color: var(--text-s); border-bottom: 1px solid var(--bdr-s); font-weight: 500;
    }
    .criteria-list li:last-child { border-bottom: none; }
    .criteria-list li::before { content: '✓'; position: absolute; left: 0; color: var(--primary); font-weight: 800; font-size: 1.1rem; }

    .prog-meta { display: flex; gap: 12px; flex-wrap: wrap; margin-top: 24px; }
    .meta-chip { 
      background: var(--digital-blue-50); color: var(--digital-blue-700); 
      font-size: .8rem; font-weight: 700; padding: 6px 16px; border-radius: 50px; border: 1px solid var(--digital-blue-100);
    }

    /* ========================================================================== */
    /* ADMISSION STEPS                                                            */
    /* ========================================================================== */
    .steps-grid { 
      display: grid; grid-template-columns: repeat(auto-fill,minmax(300px,1fr)); gap: 24px; 
    }
    .step-card {
      background: #fff; border: 1px solid var(--bdr); border-radius: var(--r-md);
      padding: 32px 24px 24px; position: relative; box-shadow: var(--sh-xs);
      transition: transform var(--t), box-shadow var(--t), border-color var(--t);
    }
    .step-card:hover { transform: translateY(-4px); box-shadow: var(--sh-md); border-color: rgba(51,133,255,0.15); }
    .step-num {
      position: absolute; top: -18px; left: 24px;
      width: 40px; height: 40px; background: var(--primary); color: #fff;
      font-family: 'Syne', sans-serif; font-weight: 800; font-size: 1.1rem;
      border-radius: 50%; display: flex; align-items: center; justify-content: center;
      box-shadow: 0 4px 12px rgba(0,102,255,0.25); transition: transform 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
    }
    .step-card:hover .step-num { transform: scale(1.15); }
    .step-card h4 { font-size: 1.05rem; font-weight: 800; color: var(--primary-d); margin-bottom: 12px; }
    .step-card p { font-size: .9rem; color: var(--text-s); margin: 0; line-height: 1.7; }

    /* ========================================================================== */
    /* IMPORTANT DATES                                                            */
    /* ========================================================================== */
    .dates-grid { 
      display: grid; grid-template-columns: repeat(auto-fill,minmax(220px,1fr)); gap: 20px; 
    }
    .date-card {
      background: #fff; border: 1px solid var(--bdr); border-radius: var(--r-md);
      padding: 24px 20px; text-align: center; border-top: 4px solid var(--gold);
      box-shadow: var(--sh-xs); transition: transform var(--t);
    }
    .date-card:hover { transform: translateY(-4px); box-shadow: var(--sh-sm); }
    .date-event { font-size: .85rem; font-weight: 700; color: var(--text-m); text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 8px; }
    .date-val { font-family: 'Syne', sans-serif; font-size: 1.3rem; font-weight: 800; color: var(--primary-d); }

    /* ========================================================================== */
    /* FEE TABLE                                                                  */
    /* ========================================================================== */
    .table-wrap { overflow-x: auto; border-radius: var(--r-md); border: 1px solid var(--bdr); box-shadow: var(--sh-sm); background: #fff;}
    table { width: 100%; border-collapse: collapse; background: #fff; }
    thead tr { background: var(--primary-l); border-bottom: 1px solid var(--bdr); }
    thead th { 
      color: var(--primary-d); font-family: 'DM Sans', sans-serif; font-size: .85rem; 
      font-weight: 800; text-transform: uppercase; letter-spacing: .05em; padding: 18px 24px; text-align: left; 
    }
    tbody td { 
      padding: 16px 24px; border-bottom: 1px solid var(--bdr-s); font-size: .95rem; 
      color: var(--text-s); vertical-align: middle; font-weight: 500;
    }
    tbody tr:last-child td { border-bottom: none; }
    tbody tr:hover td { background: var(--sur-2); }
    tbody td strong { color: var(--primary-d); font-weight: 700; }

    /* ========================================================================== */
    /* ANIMATIONS (Scroll Reveal)                                                 */
    /* ========================================================================== */
    .fade-up { opacity: 0; transform: translateY(32px); transition: opacity .6s var(--ease), transform .6s var(--ease); }
    .fade-up.visible { opacity: 1; transform: translateY(0); }
    .fade-in { opacity: 0; transition: opacity .6s var(--ease); }
    .fade-in.visible { opacity: 1; }

    .delay-1 { transition-delay: .05s; }
    .delay-2 { transition-delay: .1s; }
    .delay-3 { transition-delay: .15s; }
    .delay-4 { transition-delay: .2s; }
    .delay-5 { transition-delay: .25s; }
    .delay-6 { transition-delay: .3s; }

    @media (max-width: 768px) {
      .stats-section { padding-bottom: 40px; margin-top: -30px; }
      .stat-box { padding: 20px 12px; }
      .stat-num { font-size: 1.8rem; }
      .prog-header { flex-direction: column; text-align: center; gap: 12px; padding: 24px; }
      .prog-body { padding: 24px; }
      .criteria-list li { font-size: 0.9rem; }
    }

